#include <vector>
using namespace std;

bool solve(vector<long long> nums) {
    int n = nums.size();
    if (n < 3) return false;

    for (int p = 1; p < n - 1; ++p) {
        for (int q = p + 1; q < n - 1; ++q) {
            bool valid = true;

            // Check nums[0..p] is strictly increasing
            for (int i = 1; i <= p; ++i) {
                if (nums[i] <= nums[i-1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check nums[p..q] is strictly decreasing
            for (int i = p + 1; i <= q; ++i) {
                if (nums[i] >= nums[i-1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check nums[q..n-1] is strictly increasing
            for (int i = q + 1; i < n; ++i) {
                if (nums[i] <= nums[i-1]) {
                    valid = false;
                    break;
                }
            }
            if (valid) return true;
        }
    }

    return false;
}
